)

type Config struct {
	Port             string
	RuntimeClassName string
	EnableTLS        bool
	TLSCert          string
	TLSKey           string
	EnableAuth       bool
}

type Server struct {
	config      *Config
	storeClient store.Store
	handler     *Handler
	httpServer  *http.Server
}

func NewServer(config *Config) (*Server, error) {
	storeClient := store.Storage()
	ctx := context.Background()
	if err := storeClient.Ping(ctx); err != nil {
		return nil, err
	}

	handler, err := NewHandler(storeClient, config.EnableAuth)
