package workloadmanager

import (
	"context"
	"fmt"
	"net/http"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/hashicorp/golang-lru/v2/expirable"
	"github.com/volcano-sh/agentcube/pkg/apis/runtime/v1alpha1"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
	authenticationv1 "k8s.io/api/authentication/v1"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/rest"
	"k8s.io/klog/v2"
)

const (
	defaultIdleTimeout      = 15 * time.Minute
	gcTickInterval          = 15 * time.Second
	gcContextTimeout        = 2 * time.Minute
	sandboxCreateTimeout    = 2 * time.Minute
	sandboxCreateWaitTicker = 1 * time.Second
)

type Handler struct {
	store           store.Store
	enableAuth      bool
	k8sClient       kubernetes.Interface
	tokenCache      *expirable.LRU[string, *tokenCacheEntry]
	userClientCache *expirable.LRU[string, *dynamicClientEntry]
	gcCtx           context.Context
	gcCancel        context.CancelFunc
}

type tokenCacheEntry struct {
	username       string
	serviceAccount string
	namespace      string
	expiresAt      time.Time
}

type dynamicClientEntry struct {
	client interface{}
}

func NewHandler(storeClient store.Store, enableAuth bool) (*Handler, error) {
	h := &Handler{
		store:      storeClient,
		tokenCache: expirable.NewLRU[string, *tokenCacheEntry](1000, nil, 5*time.Minute),
	}

	if enableAuth {
		h.enableAuth = enableAuth
		config, err := rest.InClusterConfig()
		if err != nil {
			return nil, fmt.Errorf("failed to load in-cluster config: %w", err)
		}
		clientset, err := kubernetes.NewForConfig(config)
		if err != nil {
			return nil, fmt.Errorf("failed to create kubernetes client: %w", err)
		}
		h.k8sClient = clientset
		h.userClientCache = expirable.NewLRU[string, *dynamicClientEntry](100, nil, 10*time.Minute)
	}

	gcCtx, gcCancel := context.WithCancel(context.Background())
	h.gcCtx = gcCtx
	h.gcCancel = gcCancel

	return h, nil
}

func (h *Handler) RegisterRoutes(engine *gin.Engine) {
	engine.GET("/health", h.healthHandler)

	v1 := engine.Group("/v1")
	v1.Use(h.loggingMiddleware)
	if h.enableAuth {
		v1.Use(h.authMiddleware)
	}

	v1.POST("/agent-runtime", h.createAgentRuntimeHandler)
	v1.DELETE("/agent-runtime/sessions/:sessionId", h.deleteAgentRuntimeSessionHandler)
	v1.POST("/code-interpreter", h.createCodeInterpreterHandler)
	v1.DELETE("/code-interpreter/sessions/:sessionId", h.deleteCodeInterpreterSessionHandler)
}

func (h *Handler) healthHandler(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

func (h *Handler) loggingMiddleware(c *gin.Context) {
	start := time.Now()
	path := c.Request.URL.Path
	query := c.Request.URL.RawQuery

	c.Next()

	latency := time.Since(start)
	statusCode := c.Writer.Status()

	klog.Infof("[%d] %s %s %v %s", statusCode, c.Request.Method, path, latency, query)
}

func (h *Handler) authMiddleware(c *gin.Context) {
	authHeader := c.GetHeader("Authorization")
	if authHeader == "" {
		c.JSON(http.StatusUnauthorized, gin.H{"message": "Missing authorization header"})
		c.Abort()
		return
	}

	token, err := h.extractBearerToken(authHeader)
	if err != nil {
		c.JSON(http.StatusUnauthorized, gin.H{"message": err.Error()})
		c.Abort()
		return
	}

	cacheKey := token
	if entry, ok := h.tokenCache.Get(cacheKey); ok {
		if time.Now().Before(entry.expiresAt) {
			ctx := context.WithValue(c.Request.Context(), "token", token)
			ctx = context.WithValue(ctx, "username", entry.username)
			ctx = context.WithValue(ctx, "serviceAccount", entry.serviceAccount)
			ctx = context.WithValue(ctx, "namespace", entry.namespace)
			c.Request = c.Request.WithContext(ctx)
			c.Next()
			return
		}
		h.tokenCache.Remove(cacheKey)
	}

	userInfo, err := h.validateServiceAccountToken(c.Request.Context(), token)
	if err != nil {
		c.JSON(http.StatusUnauthorized, gin.H{"message": "Token validation failed: " + err.Error()})
		c.Abort()
		return
	}

	h.tokenCache.Add(cacheKey, &tokenCacheEntry{
		username:       entry.username,
		serviceAccount: entry.serviceAccount,
		namespace:      entry.namespace,
		expiresAt:      time.Now().Add(5 * time.Minute),
	})

	ctx := context.WithValue(c.Request.Context(), "token", token)
	ctx = context.WithValue(ctx, "username", userInfo.username)
	ctx = context.WithValue(ctx, "serviceAccount", userInfo.serviceAccount)
	ctx = context.WithValue(ctx, "namespace", userInfo.namespace)
	c.Request = c.Request.WithContext(ctx)
	c.Next()
}

func (h *Handler) extractBearerToken(authHeader string) (string, error) {
	const bearerPrefix = "Bearer "
	if len(authHeader) < len(bearerPrefix) || authHeader[:len(bearerPrefix)] != bearerPrefix {
		return "", fmt.Errorf("invalid authorization header format")
	}
	token := authHeader[len(bearerPrefix):]
	if token == "" {
		return "", fmt.Errorf("missing token in authorization header")
	}
	return token, nil
}

type validatedUserInfo struct {
	username       string
	serviceAccount string
	namespace      string
}

func (h *Handler) validateServiceAccountToken(ctx context.Context, token string) (*validatedUserInfo, error) {
	tokenReview := &authenticationv1.TokenReview{
		Spec: authenticationv1.TokenReviewSpec{
			Token: token,
		},
	}

	result, err := h.k8sClient.AuthenticationV1().TokenReviews().Create(ctx, tokenReview, metav1.CreateOptions{})
	if err != nil {
		return nil, fmt.Errorf("token review failed: %w", err)
	}

	if !result.Status.Authenticated {
		return nil, fmt.Errorf("token not authenticated")
	}

	username := result.Status.User.Username
	const serviceAccountPrefix = "system:serviceaccount:"
	if len(username) <= len(serviceAccountPrefix) {
		return nil, fmt.Errorf("invalid username format")
	}

	rest := username[len(serviceAccountPrefix):]
	parts := splitStringBySep(rest, ":")
	if len(parts) != 2 {
		return nil, fmt.Errorf("invalid service account username format")
	}

	return &validatedUserInfo{
		username:       username,
		serviceAccount: parts[1],
		namespace:      parts[0],
	}, nil
}

func splitStringBySep(s, sep string) []string {
	result := make([]string, 0)
	start := 0
	for i := 0; i <= len(s)-len(sep); i++ {
		if s[i:i+len(sep)] == sep {
			result = append(result, s[start:i])
			start = i + len(sep)
		}
	}
	result = append(result, s[start:])
	return result
}

func (h *Handler) createAgentRuntimeHandler(c *gin.Context) {
	h.createSandboxHandler(c, v1alpha1.AgentRuntimeKind)
}

func (h *Handler) createCodeInterpreterHandler(c *gin.Context) {
	h.createSandboxHandler(c, v1alpha1.CodeInterpreterKind)
}

func (h *Handler) createSandboxHandler(c *gin.Context, kind string) {
	var req types.CreateSandboxRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"message": "Invalid request body"})
		return
	}

	req.Kind = kind
	if err := req.Validate(); err != nil {
		apiErr, ok := err.(*types.APIError)
		if ok {
			c.JSON(apiErr.Code, gin.H{"message": apiErr.Message})
		} else {
			c.JSON(http.StatusBadRequest, gin.H{"message": err.Error()})
		}
		return
	}

	ctx := c.Request.Context()
	sessionID := fmt.Sprintf("%s-%s-%d", req.Namespace, req.Name, time.Now().UnixNano())

	sandboxInfo := &types.SandboxInfo{
		Kind:             kind,
		SandboxID:        "",
		SandboxNamespace: req.Namespace,
		Name:             req.Name,
		SessionID:        sessionID,
		Status:           "pending",
		CreatedAt:        time.Now(),
		ExpiresAt:        time.Now().Add(DefaultSandboxTTL),
	}

	if err := h.store.StoreSandbox(ctx, sandboxInfo); err != nil {
		klog.Errorf("Failed to store sandbox: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"message": "internal server error"})
		return
	}

	klog.Infof("Sandbox created: session=%s, kind=%s, namespace=%s, name=%s", sessionID, kind, req.Namespace, req.Name)

	response := &types.CreateSandboxResponse{
		SessionID:   sessionID,
		SandboxID:   sandboxInfo.SandboxID,
		SandboxName: req.Name,
		EntryPoints: []types.SandboxEntryPoint{},
	}

	c.JSON(http.StatusOK, response)
}

func (h *Handler) deleteAgentRuntimeSessionHandler(c *gin.Context) {
	h.deleteSandboxSessionHandler(c, v1alpha1.AgentRuntimeKind)
}

func (h *Handler) deleteCodeInterpreterSessionHandler(c *gin.Context) {
	h.deleteSandboxSessionHandler(c, v1alpha1.CodeInterpreterKind)
}

func (h *Handler) deleteSandboxSessionHandler(c *gin.Context, kind string) {
	sessionID := c.Param("sessionId")
	if sessionID == "" {
		c.JSON(http.StatusBadRequest, gin.H{"message": "sessionId is required"})
		return
	}

	ctx := c.Request.Context()
	sandbox, err := h.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		if err == store.ErrNotFound {
			c.JSON(http.StatusNotFound, gin.H{"message": fmt.Sprintf("Session ID %s not found, maybe already deleted", sessionID)})
			return
		}
		klog.Errorf("Failed to get sandbox: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"message": "internal server error"})
		return
	}

	_ = sandbox

	if err := h.store.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
		klog.Errorf("Failed to delete sandbox: %v", err)
		c.JSON(http.StatusInternalServerError, gin.H{"message": "internal server error"})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "Sandbox deleted successfully"})
}

