package workloadmanager

import (
	"context"
	"errors"
	"net/http"
	"os/signal"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"github.com/volcano-sh/agentcube/pkg/store"
	"golang.org/x/net/http2"
	"golang.org/x/net/http2/h2c"
	"k8s.io/klog/v2"
)

const (
	DefaultSandboxTTL         = 8 * time.Hour
	DefaultSandboxIdleTimeout = 15 * time.Minute
	gcTickInterval            = 15 * time.Second
	gcContextTimeout          = 2 * time.Minute
)

var (
	errTLSCertKeyMissing = errors.New("TLS enabled but cert/key not provided")
)

var (
	SessionIdLabelKey         = "runtime.agentcube.io/session-id"
	WorkloadNameLabelKey      = "runtime.agentcube.io/workload-name"
	SandboxNameLabelKey       = "runtime.agentcube.io/sandbox-name"
	LastActivityAnnotationKey = "last-activity-time"
	IdleTimeoutAnnotationKey  = "runtime.agentcube.io/idle-timeout"
)

type Config struct {
	Port             string
	RuntimeClassName string
	EnableTLS        bool
	TLSCert          string
	TLSKey           string
	EnableAuth       bool
}

type Server struct {
	config      *Config
	storeClient store.Store
	handler     *Handler
	httpServer  *http.Server
	gcCtx       context.Context
	gcCancel    context.CancelFunc
}

func NewServer(config *Config) (*Server, error) {
	storeClient := store.Storage()
	ctx := context.Background()
	if err := storeClient.Ping(ctx); err != nil {
		return nil, err
	}

	handler, err := NewHandler(storeClient, config.EnableAuth)
	if err != nil {
		return nil, err
	}

	gcCtx, gcCancel := context.WithCancel(context.Background())

	return &Server{
		config:      config,
		storeClient: storeClient,
		handler:     handler,
		gcCtx:       gcCtx,
		gcCancel:    gcCancel,
	}, nil
}

func (s *Server) Start() error {
	gin.SetMode(gin.ReleaseMode)
	engine := gin.New()
	engine.Use(gin.Recovery())

	s.handler.RegisterRoutes(engine)

	s.httpServer = &http.Server{
		Addr:         ":" + s.config.Port,
		Handler:      h2c.NewHandler(engine, &http2.Server{}),
		ReadTimeout:  15 * time.Second,
		IdleTimeout:  90 * time.Second,
	}

	ctx := context.Background()
	if err := s.storeClient.Ping(ctx); err != nil {
		return err
	}

	go s.startGarbageCollection()

	if s.config.EnableTLS {
		if s.config.TLSCert == "" || s.config.TLSKey == "" {
			return errTLSCertKeyMissing
		}
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}

	return s.httpServer.ListenAndServe()
}

func (s *Server) Stop(ctx context.Context) error {
	if s.gcCancel != nil {
		s.gcCancel()
	}

	if s.httpServer != nil {
		shutdownCtx, cancel := context.WithTimeout(ctx, 15*time.Second)
		defer cancel()
		if err := s.httpServer.Shutdown(shutdownCtx); err != nil {
			klog.Errorf("Error shutting down HTTP server: %v", err)
		}
	}

	if s.storeClient != nil {
		return s.storeClient.Close()
	}
	return nil
}

func (s *Server) RunWithGracefulShutdown() error {
	ctx, cancel := signal.NotifyContext(context.Background(), syscall.SIGINT, syscall.SIGTERM)
	defer cancel()

	go func() {
		<-ctx.Done()
		klog.Info("Shutting down server...")
		shutdownCtx, shutdownCancel := context.WithTimeout(context.Background(), 15*time.Second)
		defer shutdownCancel()
		if err := s.Stop(shutdownCtx); err != nil {
			klog.Errorf("Error stopping server: %v", err)
		}
	}()

	klog.Infof("Starting workload manager on port %s", s.config.Port)
	return s.Start()
}

func (s *Server) startGarbageCollection() {
	ticker := time.NewTicker(gcTickInterval)
	defer ticker.Stop()

	for {
		select {
		case <-s.gcCtx.Done():
			return
		case <-ticker.C:
			s.runGarbageCollection()
		}
	}
}

func (s *Server) runGarbageCollection() {
	gcCtx, cancel := context.WithTimeout(s.gcCtx, gcContextTimeout)
	defer cancel()

	inactiveTime := time.Now().Add(-DefaultSandboxIdleTimeout)

	inactive, err := s.storeClient.ListInactiveSandboxes(gcCtx, inactiveTime, 16)
	if err != nil {
		klog.Errorf("GC: failed to list inactive sandboxes: %v", err)
		inactive = nil
	}

	expired, err := s.storeClient.ListExpiredSandboxes(gcCtx, time.Now(), 16)
	if err != nil {
		klog.Errorf("GC: failed to list expired sandboxes: %v", err)
		expired = nil
	}

	seen := make(map[string]bool)
	toDelete := make([]*types.SandboxInfo, 0)

	for _, sandbox := range inactive {
		if !seen[sandbox.SessionID] {
			seen[sandbox.SessionID] = true
			toDelete = append(toDelete, sandbox)
		}
	}

	for _, sandbox := range expired {
		if !seen[sandbox.SessionID] {
			seen[sandbox.SessionID] = true
			toDelete = append(toDelete, sandbox)
		}
	}

	for _, sandbox := range toDelete {
		if err := s.storeClient.DeleteSandboxBySessionID(gcCtx, sandbox.SessionID); err != nil {
			klog.Errorf("GC: failed to delete sandbox %s: %v", sandbox.SessionID, err)
		} else {
			klog.Infof("GC: deleted sandbox session=%s", sandbox.SessionID)
		}
	}
}

